const gmailMessages = $input.all();
const leadInfo = $('Get Recent Outreach Emails').first().json;
const replies = [];

for (const item of gmailMessages) {
  const message = item.json;

  // Extract headers
  const headers = message.payload?.headers || [];
  const getHeader = (name) => headers.find(h => h.name === name)?.value || '';

  // Extract body
  let body = '';
  const parts = message.payload?.parts || [];
  if (parts.length > 0) {
    const textPart = parts.find(p => p.mimeType === 'text/plain');
    if (textPart?.body?.data) {
      body = Buffer.from(textPart.body.data, 'base64').toString('utf-8');
    }
  } else if (message.payload?.body?.data) {
    body = Buffer.from(message.payload.body.data, 'base64').toString('utf-8');
  }

  replies.push({
    lead_id: leadInfo.lead_id,
    org_id: leadInfo.org_id,
    company_name: leadInfo.company_name,
    reply_from: getHeader('From'),
    reply_to: getHeader('To'),
    subject: getHeader('Subject'),
    body: body || 'No body found',
    received_at: getHeader('Date') || new Date().toISOString(),
    thread_id: message.threadId || null,
    message_id: message.id || null
  });
}

return replies.length > 0 ? replies : [{
  lead_id: leadInfo.lead_id,
  org_id: leadInfo.org_id,
  company_name: leadInfo.company_name,
  reply_from: leadInfo.lead_email,
  body: 'Reply detected',
  received_at: new Date().toISOString(),
  thread_id: null
}];

const aiAnalysis = $input.first().json.output || {};
const replyData = $('Extract Reply Data').item.json;

// If output exists, use it; otherwise use direct input
const data = aiAnalysis.lead_id ? aiAnalysis : replyData;

const qualification = {
  lead_id: data.lead_id || $('Extract Reply Data').first().json?.lead_id || 92,
  org_id: data.org_id || 1,
  company_name: data.company_name || 'Unknown',
  reply_from: data.reply_from || '',
  reply_to: data.reply_to || '',
  subject: data.subject || '',
  body: data.body || '',
  received_at: data.received_at || new Date().toISOString(),
  thread_id: data.thread_id || null,
  sentiment: aiAnalysis.sentiment || 'neutral',
  intent: aiAnalysis.intent || 'unknown',
  urgency: aiAnalysis.urgency || 'normal',
  budget_mentioned: aiAnalysis.budget_mentioned || false,
  budget_info: aiAnalysis.budget_info || null,
  timeline_mentioned: aiAnalysis.timeline_mentioned || null,
  pain_points_mentioned: aiAnalysis.pain_points || [],
  decision_maker_confirmed: aiAnalysis.decision_maker_confirmed || false,
  qualification_score: aiAnalysis.qualification_score || 50,
  interest_level: aiAnalysis.interest_level || 'cold',
  next_action: aiAnalysis.next_action || 'nurture',
  recommended_response: aiAnalysis.recommended_response || '',
  key_insights: aiAnalysis.key_insights || '',
  red_flags: aiAnalysis.red_flags || [],
  ai_confidence: aiAnalysis.confidence || 0,
  processed: true,
  processed_at: new Date().toISOString()
};

let qualificationStatus;
if (qualification.qualification_score >= 70) qualificationStatus = 'qualified';
else if (qualification.qualification_score >= 40) qualificationStatus = 'warm';
else if (qualification.sentiment === 'not_interested' || qualification.intent === 'unsubscribe') qualificationStatus = 'disqualified';
else qualificationStatus = 'cold';

qualification.qualification_status = qualificationStatus;
qualification.sales_ready = (
  qualification.qualification_score >= 70 &&
  ['interested', 'question'].includes(qualification.sentiment) &&
  !['unsubscribe', 'decline'].includes(qualification.intent)
);

return qualification;

const error = $input.first().json;

console.error('Reply Detection Error:', {
  workflow: 'Reply Detection',
  node: error.node?.name,
  error: error.error?.message,
  timestamp: new Date().toISOString()
});

// Could also insert to error log table
return {
  workflow: 'Reply Detection',
  error_message: error.error?.message,
  node_name: error.node?.name,
  timestamp: new Date().toISOString()
};
